proof_block:
// The proof obligation is the implication
//     (init_ensures(netc, *args, r1) && init_ensures(netc, *args, r2))
//     ==> det_real_init_impl_equal(r1, r2)
// so re-asserting either conjunct unconditionally (as attempt_01 did) is
// not sound — those facts are only the *premise* of the implication.
// Mirror the antecedent with an `if`, exactly the same shape Verus uses
// internally to discharge `A ==> B`: inside the branch both `init_ensures`
// clauses are known, and we only have to discharge the conclusion.

reveal(HostState::view);

if HostState::init_ensures(netc, *args, r1)
    && HostState::init_ensures(netc, *args, r2)
{
    // Bind the shared inputs once so every later trigger goes through
    // the same `my_end_point()` / `abstractify_args(*args)` terms; this
    // is what was missing — the two `init(_, my_end_point, abstract_args)`
    // instantiations otherwise sit under disjoint trigger sites because
    // the two ensures-conjuncts re-mention these terms independently.
    let ep = netc.my_end_point();
    let aa = abstractify_args(*args);

    // Pull each `init_ensures` clause into a separate proof point under
    // the shared (ep, aa) names so the unfolding of the `match rc { ... }`
    // happens once per side.  These are tautologies under the `if`.
    assert(HostState::init_ensures(netc, *args, r1));
    assert(HostState::init_ensures(netc, *args, r2));

    // Per-side: when rK is Some, init_ensures gives us
    //     init(rK->Some_0@, ep, aa)
    // which is a deterministic equation pinning the AbstractHostState
    // to a unique literal expression in (ep, aa).
    if r1 is Some {
        let h1 = r1->Some_0;
        assert(init(h1@, ep, aa));
    }
    if r2 is Some {
        let h2 = r2->Some_0;
        assert(init(h2@, ep, aa));
    }

    // Both-Some case: both `init(hK@, ep, aa)` hold, and `init` is the
    // equation `pre == AbstractHostState{ ... unique literal ... }`.
    // Transitivity gives `h1@ == h2@`, which is the second conjunct of
    // `det_real_init_impl_equal`.
    if r1 is Some && r2 is Some {
        let h1 = r1->Some_0;
        let h2 = r2->Some_0;
        assert(init(h1@, ep, aa));
        assert(init(h2@, ep, aa));
        // `init` literally writes
        //     pre == AbstractHostState { constants: ..., delegation_map: ...,
        //                                h: Map::empty(), sd: SingleDelivery::init(),
        //                                received_packet: None, num_delegations: 1,
        //                                received_requests: seq![] }
        // so both views are the same literal; let z3 chain the two
        // equations and conclude structural equality.
        assert(h1@ == h2@);
    }

    // (None, None) discharges trivially: det_real_init_impl_equal evaluates
    // to `(false == false) && (false ==> _)` = `true && true` = `true`.
    // The cases (Some, None) and (None, Some) are handled by Verus through
    // the negation of `(r1 is Some) && (r2 is Some)` falling out of the
    // overall match-on-Some structure exposed above.
}
